const http = require('http');
const WebSocket = require('ws');
const crypto = require('crypto');

const PORT = process.env.PORT || 8080;
const TICK_RATE = 10;
const MAP_WIDTH = 2000;
const MAP_HEIGHT = 2000;
const START_RESOURCES = 1000;
const UNIT_SPEED = 80;
const ATTACK_RANGE = 120;
const ATTACK_DAMAGE = 10;
const ATTACK_COOLDOWN_MS = 800;
const GATHER_RATE = 5;
const BUILD_DISTANCE = 180;

const UNIT_TYPES = {
  worker: {
    hp: 50,
    speed: 70,
    damage: 4,
    range: 40,
    cooldown: 900,
    cost: 50,
  },
  soldier: {
    hp: 100,
    speed: 80,
    damage: 12,
    range: 120,
    cooldown: 800,
    cost: 100,
  },
  tank: {
    hp: 250,
    speed: 45,
    damage: 30,
    range: 180,
    cooldown: 1400,
    cost: 250,
  },
};

const BUILDING_TYPES = {
  base: {
    hp: 1000,
    cost: 0,
    canTrain: ['worker', 'soldier'],
  },
  barracks: {
    hp: 600,
    cost: 300,
    canTrain: ['soldier', 'tank'],
  },
  refinery: {
    hp: 400,
    cost: 200,
    canTrain: [],
  },
};

const server = http.createServer();
const wss = new WebSocket.Server({ server });

const game = {
  players: new Map(),
  units: new Map(),
  buildings: new Map(),
  resources: new Map(),
  nextEntityId: 1,
  startedAt: Date.now(),
};

function id(prefix) {
  return `${prefix}_${game.nextEntityId++}`;
}

function clamp(v, min, max) {
  return Math.max(min, Math.min(max, v));
}

function dist(a, b) {
  const dx = a.x - b.x;
  const dy = a.y - b.y;
  return Math.sqrt(dx * dx + dy * dy);
}

function now() {
  return Date.now();
}

function safeSend(ws, payload) {
  if (ws.readyState === WebSocket.OPEN) {
    ws.send(JSON.stringify(payload));
  }
}

function broadcast(payload) {
  const msg = JSON.stringify(payload);
  for (const player of game.players.values()) {
    if (player.ws.readyState === WebSocket.OPEN) {
      player.ws.send(msg);
    }
  }
}

function createPlayer(ws) {
  const playerId = crypto.randomUUID();
  const spawnX = 200 + Math.random() * (MAP_WIDTH - 400);
  const spawnY = 200 + Math.random() * (MAP_HEIGHT - 400);

  const player = {
    id: playerId,
    ws,
    name: `Player-${playerId.slice(0, 6)}`,
    resources: START_RESOURCES,
    connectedAt: now(),
  };

  game.players.set(playerId, player);

  const baseId = createBuilding(playerId, 'base', spawnX, spawnY);
  createUnit(playerId, 'worker', spawnX + 60, spawnY + 20);
  createUnit(playerId, 'worker', spawnX + 20, spawnY + 60);
  createUnit(playerId, 'soldier', spawnX + 80, spawnY + 80);

  return { player, baseId };
}

function createUnit(ownerId, type, x, y) {
  const def = UNIT_TYPES[type];
  if (!def) return null;

  const entity = {
    id: id('u'),
    kind: 'unit',
    ownerId,
    type,
    x: clamp(x, 0, MAP_WIDTH),
    y: clamp(y, 0, MAP_HEIGHT),
    hp: def.hp,
    maxHp: def.hp,
    speed: def.speed,
    damage: def.damage,
    range: def.range,
    cooldown: def.cooldown,
    lastAttackAt: 0,
    targetId: null,
    moveTarget: null,
    gatherTargetId: null,
  };

  game.units.set(entity.id, entity);
  return entity.id;
}

function createBuilding(ownerId, type, x, y) {
  const def = BUILDING_TYPES[type];
  if (!def) return null;

  const entity = {
    id: id('b'),
    kind: 'building',
    ownerId,
    type,
    x: clamp(x, 0, MAP_WIDTH),
    y: clamp(y, 0, MAP_HEIGHT),
    hp: def.hp,
    maxHp: def.hp,
  };

  game.buildings.set(entity.id, entity);
  return entity.id;
}

function createResourceNode(x, y, amount = 5000) {
  const entity = {
    id: id('r'),
    kind: 'resource',
    x: clamp(x, 0, MAP_WIDTH),
    y: clamp(y, 0, MAP_HEIGHT),
    amount,
  };
  game.resources.set(entity.id, entity);
  return entity.id;
}

function getEntity(entityId) {
  return game.units.get(entityId) || game.buildings.get(entityId) || game.resources.get(entityId) || null;
}

function removeEntity(entityId) {
  if (game.units.delete(entityId)) return true;
  if (game.buildings.delete(entityId)) return true;
  if (game.resources.delete(entityId)) return true;
  return false;
}

function serializeStateFor(playerId) {
  return {
    type: 'state',
    you: playerId,
    map: { width: MAP_WIDTH, height: MAP_HEIGHT },
    players: Array.from(game.players.values()).map(p => ({
      id: p.id,
      name: p.name,
      resources: p.resources,
    })),
    units: Array.from(game.units.values()),
    buildings: Array.from(game.buildings.values()),
    resources: Array.from(game.resources.values()),
    serverTime: now(),
  };
}

function handleBuild(player, msg) {
  const { buildingType, x, y, builderId } = msg;
  const def = BUILDING_TYPES[buildingType];
  if (!def) return;

  if (player.resources < def.cost) {
    safeSend(player.ws, { type: 'error', message: 'Not enough resources' });
    return;
  }

  let canBuild = true;
  if (builderId) {
    const builder = game.units.get(builderId);
    if (!builder || builder.ownerId !== player.id || builder.type !== 'worker') {
      canBuild = false;
    } else {
      const d = dist(builder, { x, y });
      if (d > BUILD_DISTANCE) canBuild = false;
    }
  }

  if (!canBuild) {
    safeSend(player.ws, { type: 'error', message: 'Invalid builder or too far away' });
    return;
  }

  player.resources -= def.cost;
  const buildingId = createBuilding(player.id, buildingType, x, y);
  broadcast({
    type: 'event',
    event: 'building_created',
    building: game.buildings.get(buildingId),
    playerId: player.id,
  });
}

function handleMove(player, msg) {
  const { unitIds, x, y } = msg;
  if (!Array.isArray(unitIds)) return;

  for (const unitId of unitIds) {
    const unit = game.units.get(unitId);
    if (!unit || unit.ownerId !== player.id) continue;
    unit.moveTarget = {
      x: clamp(x + (Math.random() * 20 - 10), 0, MAP_WIDTH),
      y: clamp(y + (Math.random() * 20 - 10), 0, MAP_HEIGHT),
    };
    unit.targetId = null;
    unit.gatherTargetId = null;
  }

  broadcast({
    type: 'event',
    event: 'units_moved',
    playerId: player.id,
    unitIds,
    x,
    y,
  });
}

function handleAttack(player, msg) {
  const { unitIds, targetId } = msg;
  if (!Array.isArray(unitIds) || !targetId) return;

  const target = getEntity(targetId);
  if (!target || target.kind === 'resource') return;

  for (const unitId of unitIds) {
    const unit = game.units.get(unitId);
    if (!unit || unit.ownerId !== player.id) continue;
    unit.targetId = targetId;
    unit.moveTarget = null;
    unit.gatherTargetId = null;
  }

  broadcast({
    type: 'event',
    event: 'attack_order',
    playerId: player.id,
    unitIds,
    targetId,
  });
}

function handleTrain(player, msg) {
  const { buildingId, unitType } = msg;
  const building = game.buildings.get(buildingId);
  const unitDef = UNIT_TYPES[unitType];
  if (!building || building.ownerId !== player.id || !unitDef) return;

  const buildingDef = BUILDING_TYPES[building.type];
  if (!buildingDef.canTrain.includes(unitType)) {
    safeSend(player.ws, { type: 'error', message: 'Building cannot train this unit' });
    return;
  }

  if (player.resources < unitDef.cost) {
    safeSend(player.ws, { type: 'error', message: 'Not enough resources' });
    return;
  }

  player.resources -= unitDef.cost;
  const unitId = createUnit(player.id, unitType, building.x + 40 + Math.random() * 30, building.y + 40 + Math.random() * 30);
  broadcast({
    type: 'event',
    event: 'unit_created',
    playerId: player.id,
    unit: game.units.get(unitId),
  });
}

function handleGather(player, msg) {
  const { unitIds, resourceId } = msg;
  const resource = game.resources.get(resourceId);
  if (!resource) return;

  for (const unitId of unitIds || []) {
    const unit = game.units.get(unitId);
    if (!unit || unit.ownerId !== player.id || unit.type !== 'worker') continue;
    unit.gatherTargetId = resourceId;
    unit.targetId = null;
    unit.moveTarget = null;
  }

  broadcast({
    type: 'event',
    event: 'gather_order',
    playerId: player.id,
    unitIds,
    resourceId,
  });
}

function handleSetName(player, msg) {
  const name = String(msg.name || '').trim().slice(0, 24);
  if (!name) return;
  player.name = name;
  broadcast({
    type: 'event',
    event: 'player_renamed',
    playerId: player.id,
    name: player.name,
  });
}

function handleMessage(player, raw) {
  let msg;
  try {
    msg = JSON.parse(raw.toString());
  } catch {
    safeSend(player.ws, { type: 'error', message: 'Invalid JSON' });
    return;
  }

  if (!msg || typeof msg !== 'object') return;

  switch (msg.type) {
    case 'build':
      handleBuild(player, msg);
      break;
    case 'move':
      handleMove(player, msg);
      break;
    case 'attack':
      handleAttack(player, msg);
      break;
    case 'train':
      handleTrain(player, msg);
      break;
    case 'gather':
      handleGather(player, msg);
      break;
    case 'set_name':
      handleSetName(player, msg);
      break;
    case 'ping':
      safeSend(player.ws, { type: 'pong', serverTime: now() });
      break;
    default:
      safeSend(player.ws, { type: 'error', message: 'Unknown command type' });
      break;
  }
}

function moveUnitTowards(unit, targetX, targetY, dt) {
  const dx = targetX - unit.x;
  const dy = targetY - unit.y;
  const d = Math.sqrt(dx * dx + dy * dy);
  if (d < 1) {
    unit.x = targetX;
    unit.y = targetY;
    return true;
  }

  const step = unit.speed * dt;
  if (step >= d) {
    unit.x = targetX;
    unit.y = targetY;
    return true;
  }

  unit.x += (dx / d) * step;
  unit.y += (dy / d) * step;
  return false;
}

function damageEntity(target, amount) {
  target.hp -= amount;
  if (target.hp <= 0) {
    const destroyed = { ...target };
    removeEntity(target.id);
    broadcast({
      type: 'event',
      event: 'entity_destroyed',
      entity: destroyed,
    });
    return true;
  }
  return false;
}

function updateUnits(dt) {
  const t = now();

  for (const unit of game.units.values()) {
    if (unit.gatherTargetId) {
      const resource = game.resources.get(unit.gatherTargetId);
      const owner = game.players.get(unit.ownerId);
      if (!resource || !owner) {
        unit.gatherTargetId = null;
      } else {
        const d = dist(unit, resource);
        if (d > 30) {
          moveUnitTowards(unit, resource.x, resource.y, dt);
        } else {
          const gathered = Math.min(resource.amount, GATHER_RATE * dt);
          resource.amount -= gathered;
          owner.resources += gathered;
          if (resource.amount <= 0) {
            const depleted = { ...resource };
            game.resources.delete(resource.id);
            broadcast({
              type: 'event',
              event: 'resource_depleted',
              resource: depleted,
            });
            unit.gatherTargetId = null;
          }
        }
      }
    } else if (unit.targetId) {
      const target = getEntity(unit.targetId);
      if (!target || target.ownerId === unit.ownerId) {
        unit.targetId = null;
      } else {
        const d = dist(unit, target);
        if (d > unit.range) {
          moveUnitTowards(unit, target.x, target.y, dt);
        } else if (t - unit.lastAttackAt >= unit.cooldown) {
          unit.lastAttackAt = t;
          const destroyed = damageEntity(target, unit.damage);
          broadcast({
            type: 'event',
            event: 'entity_damaged',
            attackerId: unit.id,
            targetId: target.id,
            damage: unit.damage,
            destroyed,
          });
          if (destroyed) {
            unit.targetId = null;
          }
        }
      }
    } else if (unit.moveTarget) {
      const arrived = moveUnitTowards(unit, unit.moveTarget.x, unit.moveTarget.y, dt);
      if (arrived) {
        unit.moveTarget = null;
      }
    }
  }
}

function snapshotBroadcast() {
  broadcast({
    type: 'snapshot',
    serverTime: now(),
    players: Array.from(game.players.values()).map(p => ({
      id: p.id,
      name: p.name,
      resources: p.resources,
    })),
    units: Array.from(game.units.values()),
    buildings: Array.from(game.buildings.values()),
    resources: Array.from(game.resources.values()),
  });
}

function seedResources() {
  for (let i = 0; i < 20; i++) {
    createResourceNode(
      100 + Math.random() * (MAP_WIDTH - 200),
      100 + Math.random() * (MAP_HEIGHT - 200),
      3000 + Math.random() * 4000
    );
  }
}

wss.on('connection', ws => {
  const { player, baseId } = createPlayer(ws);

  safeSend(ws, {
    type: 'welcome',
    playerId: player.id,
    baseId,
    tickRate: TICK_RATE,
  });

  safeSend(ws, serializeStateFor(player.id));

  broadcast({
    type: 'event',
    event: 'player_joined',
    player: {
      id: player.id,
      name: player.name,
      resources: player.resources,
    },
  });

  ws.on('message', data => {
    handleMessage(player, data);
  });

  ws.on('close', () => {
    game.players.delete(player.id);
    for (const [unitId, unit] of game.units) {
      if (unit.ownerId === player.id) game.units.delete(unitId);
    }
    for (const [buildingId, building] of game.buildings) {
      if (building.ownerId === player.id) game.buildings.delete(buildingId);
    }
    broadcast({
      type: 'event',
      event: 'player_left',
      playerId: player.id,
    });
  });

  ws.on('error', () => {});
});

seedResources();

let lastTick = now();
setInterval(() => {
  const current = now();
  const dt = Math.min(0.25, (current - lastTick) / 1000);
  lastTick = current;
  updateUnits(dt);
  snapshotBroadcast();
}, 1000 / TICK_RATE);

